import{bV as o,aL as a,u as c,G as l}from"./chunks/framework.BfzMay2U.js";const p=JSON.parse('{"title":"配置中心的重要性","description":"","frontmatter":{"title":"配置中心的重要性","date":"2023-01-15T21:30:10.000Z","categories":["Deploy"],"tags":["consul","raft"]},"headers":[],"relativePath":"views/deploy/consul-config-center.md","filePath":"views/deploy/consul-config-center.md"}'),r={name:"views/deploy/consul-config-center.md"};function i(d,e,t,n,s,h){return a(),c("div",null,[...e[0]||(e[0]=[l('<h1 id="配置中心的重要性" tabindex="-1">配置中心的重要性 <a class="header-anchor" href="#配置中心的重要性" aria-label="Permalink to &quot;配置中心的重要性&quot;">​</a></h1><h2 id="传统配置文件的弊端" tabindex="-1">传统配置文件的弊端 <a class="header-anchor" href="#传统配置文件的弊端" aria-label="Permalink to &quot;传统配置文件的弊端&quot;">​</a></h2><ul><li>静态化配置，例如<code>.env</code>文件</li><li>配置文件无法区分环境，需要手动来维护，认为修改，容易有失误</li><li>配置文件过于分散，多模块配置信息不一样，甚至格式不一样，难以管理</li><li>历史版本无法追溯</li></ul><h2 id="微服务配置中心" tabindex="-1">微服务配置中心 <a class="header-anchor" href="#微服务配置中心" aria-label="Permalink to &quot;微服务配置中心&quot;">​</a></h2><ul><li>配置信息的管理</li><li>配置信息的查看、读取和更新等</li><li>配置信息的管理界面</li></ul><h2 id="主流的配置中心" tabindex="-1">主流的配置中心 <a class="header-anchor" href="#主流的配置中心" aria-label="Permalink to &quot;主流的配置中心&quot;">​</a></h2><ul><li><code>Apollo</code>是由携程开源的分布式配置中心，实时生效，支持灰度发布，对所有配置进行版本管理和操作审计 ，提供开放平台 API，使用人较多，网上资料也会比较丰富</li><li><code>Spring Cloud Config</code>能和<code>spring</code>框架能无缝集成，使用比较方便，没有可视化的操作界面，配置的生效也不是实时的，需要重启才能刷新</li><li><code>consul</code>，内置了<code>kv</code>存储，追寻<code>cp</code>原则，保证数据的强一致性，所以当数据在同步时，或者领导者挂了之后，<code>server</code>在重新选举的时候是不可用的，不支持配置信息历史版本的管理，用起来会比较简单</li></ul><h2 id="consul-支持配置中心的实现" tabindex="-1">consul 支持配置中心的实现 <a class="header-anchor" href="#consul-支持配置中心的实现" aria-label="Permalink to &quot;consul 支持配置中心的实现&quot;">​</a></h2><p>可以直接在管理界面直接去<code>key/value</code>创建即可，先创建一个<code>demoService/</code>的文件夹，用于为<code>demoService</code>服务提供配置信息存储，点击进去之后，再创建环境<code>dev/</code>和<code>pro/</code>测试和生产环境的文件夹，可能会连接多个数据库，所以我们在新建一个<code>demo/</code>的数据库的文件夹，<code>consul</code>如果加上<code>/</code>则是创建文件夹，不加则是对应的配置信息的<code>key</code></p><h2 id="服务注册" tabindex="-1">服务注册 <a class="header-anchor" href="#服务注册" aria-label="Permalink to &quot;服务注册&quot;">​</a></h2><p>相关文档地址：<a href="https://developer.hashicorp.com/consul/api-docs/agent/service#register-service" target="_blank" rel="noreferrer">https://developer.hashicorp.com/consul/api-docs/agent/service#register-service</a></p>',11)])])}const f=o(r,[["render",i]]);export{p as __pageData,f as default};
